    if (n == 0) return 0;
    if (n == 1) return 0;

    // BFS to find the minimum number of jumps
    vector<int> dist(n, -1);
    queue<int> q;
    q.push(0);
    dist[0] = 0;

    while (!q.empty()) {
        int i = q.front();
        q.pop();

        // Check if we have reached the end
        if (i == n - 1) break;

        // Move to adjacent cells
        for (int j : {i - 1, i + 1}) {
            if (j >= 0 && j < n && dist[j] == -1) {
                dist[j] = dist[i] + 1;
                q.push(j);
            }
        }

        // Check if current number is a prime
        long long num = nums[i];
        if (isPrime(num)) {
            // Find all indices j where nums[j] % num == 0
            set<int> indices;
            for (int j = 0; j < n; ++j) {
                if (nums[j] % num == 0 && j != i) {
                    indices.insert(j);
                }
            }

            // Jump to all those indices
            for (int j : indices) {
                if (dist[j] == -1) {
                    dist[j] = dist[i] + 1;
                    q.push(j);
                }
            }
        }
    }

    return dist[n - 1];
}

